-// Rewrite x - MIN_INT as x ^ MIN_INT (integer variant)
-instruct subI_reg_min(iRegINoSp dst, iRegIorL2I src1, immI_MIN src2) %{
-  match(Set dst (SubI src1 src2));
-
-  ins_cost(INSN_COST);
-  format %{ "eorw  $dst, $src1, #0x80000000\t# int sub MIN_VALUE as xor" %}
-
-  ins_encode %{
-    __ eorw(as_Register($dst$$reg),
-            as_Register($src1$$reg),
-            (uint64_t)0x80000000);
-  %}
-
-  ins_pipe(ialu_reg_imm);
-%}
