-// Rewrite x - MIN_INT as x ^ MIN_INT (long variant)
-instruct subL_reg_min(iRegLNoSp dst, iRegL src1, immL_MIN src2) %{
-  match(Set dst (SubL src1 src2));
-
-  ins_cost(INSN_COST);
-  format %{ "eor  $dst, $src1, #0x8000000000000000\t# long sub MIN_VALUE as xor" %}
-
-  ins_encode %{
-    __ eor(as_Register($dst$$reg),
-           as_Register($src1$$reg),
-           (uint64_t)0x8000000000000000);
-  %}
